import { ObjectId } from 'mongodb';
import { Document, model, Schema } from 'mongoose';

interface Recurrence {
  type: 'daily' | 'weekly' | 'custom';
  daysOfWeek?: number[];
  time: string; // "08:30" (UTC+7)
}

interface ITask extends Document {
  groupId: ObjectId;
  title: string;
  description: string;
  assignees: ObjectId[];
  rotationIndex: number;
  unavailableMembers?: ObjectId[];
  recurrence: Recurrence;
  status: 'active' | 'paused';
}

const taskSchema = new Schema<ITask>({
  groupId: { type: Schema.Types.ObjectId, required: true, ref: 'Group' },
  title: { type: String, required: true },
  description: { type: String, required: true },
  assignees: { type: [Schema.Types.ObjectId], required: true, ref: 'User' },
  rotationIndex: { type: Number, required: true },
  unavailableMembers: { type: [Schema.Types.ObjectId], ref: 'User' },
  recurrence: {
    type: {
      type: String,
      enum: ['daily', 'weekly', 'custom'],
      required: true
    },
    daysOfWeek: { type: [Number] },
    time: { type: String, required: true }
  },
  status: {
    type: String,
    enum: ['active', 'paused'],
    required: true
  }
});

export const TaskModel = model<ITask>('Task', taskSchema);

import { ObjectId } from 'mongodb';

interface TaskDTO {
  id: ObjectId;
  groupId: ObjectId;
  title: string;
  description: string;
  assignees: ObjectId[];
  rotationIndex: number;
  unavailableMembers?: ObjectId[];
  recurrence: {
    type: 'daily' | 'weekly' | 'custom';
    daysOfWeek?: number[];
    time: string;
  };
  status: 'active' | 'paused';
}

// Mapping logic between Model and DTO if needed

export function toTaskDTO(task: any): TaskDTO {
  return {
    id: task._id,
    groupId: task.groupId,
    title: task.title,
    description: task.description,
    assignees: task.assignees,
    rotationIndex: task.rotationIndex,
    unavailableMembers: task.unavailableMembers,
    recurrence: task.recurrence,
    status: task.status,
  };
}

import * as z from 'zod';

export const taskValidator = z.object({
  title: z.string().min(1).max(100),
  description: z.string(),
  groupId: z.string().uuid(),
  assignees: z.array(z.string().uuid()),
  rotationIndex: z.number().min(0),
  unavailableMembers: z.array(z.string().uuid()).optional(),
  recurrence: z.object({
    type: z.enum(['daily', 'weekly', 'custom']),
    daysOfWeek: z.array(z.number().min(0).max(6)).optional(),
    time: z.string().refine((time) => /^\d{2}:\d{2}$/.test(time), {
      message: "Invalid time format, expected HH:MM UTC+7"
    })
  }),
  status: z.enum(['active', 'paused'])
});

import { TaskModel } from './model';
import { ITask } from './model';

export class TaskRepository {
  async create(task: Partial<ITask>): Promise<ITask> {
    const newTask = new TaskModel(task);
    return await newTask.save();
  }

  async update(id: string, taskUpdates: Partial<ITask>): Promise<ITask | null> {
    return await TaskModel.findByIdAndUpdate(id, taskUpdates, { new: true });
  }

  async findById(id: string): Promise<ITask | null> {
    return await TaskModel.findById(id);
  }

  async updateAvailability(id: string, unavailableMembers: string[]): Promise<ITask | null> {
    return await TaskModel.findByIdAndUpdate(id, { unavailableMembers }, { new: true });
  }

  // Other repository methods as needed
}

import { TaskRepository } from './repository';
import { TaskDTO, toTaskDTO } from './dto';
import { ITask } from './model';

export class TaskService {
  private taskRepository: TaskRepository;

  constructor() {
    this.taskRepository = new TaskRepository();
  }

  async createTask(taskData: Partial<ITask>): Promise<TaskDTO> {
    const task = await this.taskRepository.create(taskData);
    return toTaskDTO(task);
  }

  async updateTask(id: string, taskData: Partial<ITask>): Promise<TaskDTO | null> {
    const task = await this.taskRepository.update(id, taskData);
    return task ? toTaskDTO(task) : null;
  }

  async updateTaskAvailability(id: string, unavailableMembers: string[]): Promise<TaskDTO | null> {
    const task = await this.taskRepository.updateAvailability(id, unavailableMembers);
    return task ? toTaskDTO(task) : null;
  }

  // Additional business logic methods
}

import { Request, Response, NextFunction } from 'express';
import { TaskService } from './service';
import { taskValidator } from './validator';
import { RequestHandler } from 'express';

const taskService = new TaskService();

export const createTask: RequestHandler = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const validationResult = taskValidator.safeParse(req.body);
    if (!validationResult.success) {
      return res.status(400).json({ message: 'Invalid input', errors: validationResult.error.errors });
    }

    // Other business logic here

    const taskDTO = await taskService.createTask(req.body);
    res.status(201).json(taskDTO);
  } catch (error) {
    next(error);
  }
};

export const updateTaskAvailability: RequestHandler = async (req: Request, res: Response, next: NextFunction) => {
  try {
    const { id } = req.params;
    const { unavailableMembers } = req.body;

    const taskDTO = await taskService.updateTaskAvailability(id, unavailableMembers);
    if (!taskDTO) {
      return res.status(404).json({ message: 'Task not found' });
    }

    res.status(200).json(taskDTO);
  } catch (error) {
    next(error);
  }
};

